#!/bin/bash
#
# Verify that every Markdown file under directories that ESQL tests
# manage as fully-generated content carries the standard "this is
# generated, do not edit" header.
#
# When the ESQL test suite regenerates docs it wipes the contents of
# these directories and replaces them. Static files placed there by
# mistake are silently deleted on the next run (see issue noted in
# EsqlFunctionPlugin.syncSnippets). This script is a guardrail: any
# file lacking the header is either an accidentally hand-written file
# in the wrong place, or a generator that forgot to emit the marker.
#
# Run from the repository root.

set -euo pipefail

ROOT="docs/reference/query-languages/esql/_snippets"
EXPECTED_PATTERN='^% This is generated by ESQL'

# Directories whose every *.md file must be generator-marked.
GENERATED_DIRS=(
    "$ROOT/functions"
    "$ROOT/operators/types"
    "$ROOT/operators/examples"
    "$ROOT/operators/detailedDescription"
    "$ROOT/commands/types"
    "$ROOT/commands/settings"
)

# commands/examples holds hand-written csv-spec subdirectories whose
# *contents* are generated. Subdirs themselves are stable; the .md files
# inside them are not.
EXAMPLES_DIR="$ROOT/commands/examples"

errors=0

check_file() {
    local file="$1"
    if [ ! -s "$file" ]; then
        echo "ERROR: empty file in generated location: $file"
        errors=$((errors + 1))
        return
    fi
    if ! head -n 1 "$file" | grep -q "$EXPECTED_PATTERN"; then
        echo "ERROR: missing generated-doc header: $file"
        errors=$((errors + 1))
    fi
}

for dir in "${GENERATED_DIRS[@]}"; do
    if [ -d "$dir" ]; then
        while IFS= read -r -d '' f; do
            check_file "$f"
        done < <(find "$dir" -type f -name '*.md' -print0)
    fi
done

if [ -d "$EXAMPLES_DIR" ]; then
    while IFS= read -r -d '' f; do
        check_file "$f"
    done < <(find "$EXAMPLES_DIR" -mindepth 2 -type f -name '*.md' -path '*.csv-spec/*' -print0)
fi

if [ "$errors" -gt 0 ]; then
    cat <<EOF

Found $errors file(s) under dynamically-generated ESQL doc directories
that do not start with the expected header:

    $EXPECTED_PATTERN

These directories are managed by ESQL test generators (see
DocsV3Support.java and EsqlFunctionPlugin.java). Any file checked in
without the header is either:

  - a hand-written file placed in the wrong directory (it will be
    silently deleted on the next full test run), or
  - produced by a generator that is missing the warning marker
    (the generator should be fixed to emit it).

See docs/reference/query-languages/esql/README.md for the layout of
hand-written vs. generated content.
EOF
    exit 1
fi

echo "OK: all files in dynamically-generated ESQL doc locations carry the expected header."
